  ('legacy-sco-62', '62', 'science', '1', 'Waves, Light and Sound', 'SC_G1_ST1_4_AV_006', '[ELO4 - Attitudes/Values] Participate actively in classroom discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves, Light and Sound', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-63', '63', 'science', '1', 'Waves, Light and Sound', 'SC_G1_ST1_4_AV_007', '[ELO4 - Attitudes/Values] Demonstrate interest and curiosity regarding the ways in which communication devices have evolved over history.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves, Light and Sound', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-64', '64', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_001', '[ELO1 - Knowledge] Define the terms: Mimic/mimicking, Protection, Living things, Non-living things, Defence, Camouflage, Grow, Nutrients, Predators', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-65', '65', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_002', '[ELO1 - Knowledge] Name and describe some living and non-living things in the environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-66', '66', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_003', '[ELO1 - Knowledge] Identify and name some characteristics of living things (e.g. they grow, need nutrients and reproduce).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-67', '67', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_004', '[ELO1 - Knowledge] Name and describe the external parts of local animals and plants and discuss their functions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-68', '68', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_005', '[ELO1 - Knowledge] Identify and describe natural defences that local animals use to help them survive (spines, camouflage etc.).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-69', '69', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_006', '[ELO1 - Knowledge] Describe mimicking in their own words (possibly copy).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-70', '70', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_007', '[ELO1 - Knowledge] Give examples of how humans mimic plants and/or animals to solve problems.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-71', '71', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_K_008', '[ELO1 - Knowledge] Identify some human problems that have been solved by mimicking how plants and /or animals use their external parts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-72', '72', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_S_001', '[ELO1 - Skills] Classify some common things as either: living or non-living.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-73', '73', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_S_002', '[ELO1 - Skills] Observe examples of how plants and/or animals use their external parts for survival, growth and to meet their needs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-74', '74', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_S_003', '[ELO1 - Skills] Communicate properties of mimicked plants and animals by observing and describing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-75', '75', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_S_004', '[ELO1 - Skills] Use simple materials to design a solution to a human problem using examples from the external parts of plants and or animals.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-76', '76', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_S_005', '[ELO1 - Skills] Construct a simple model of a gadget designed to solve the problem and test its effectiveness.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-77', '77', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_001', '[ELO1 - Attitudes/Values] Appreciate that the external parts of plants and animals have inspired technological designs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-78', '78', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_002', '[ELO1 - Attitudes/Values] Demonstrate a continuing interest and more informed curiosity in the link between nature and technological design.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-79', '79', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_003', '[ELO1 - Attitudes/Values] Willingly participate in classroom discussions and group activities with peers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-80', '80', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_004', '[ELO1 - Attitudes/Values] Show a respect for living things while making observations of any live animal or plant specimen.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-81', '81', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_005', '[ELO1 - Attitudes/Values] Observe all applicable safety measures when interacting with plant/animal specimens or using tools.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-82', '82', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_1_AV_006', '[ELO1 - Attitudes/Values] Display sensitivity and offer assistance to peers who may have physical or learning challenges when conducting practical and group work.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-83', '83', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_K_001', '[ELO2 - Knowledge] Define the terms: Protect, Signal, Offspring, Survive, Behaviour, Parents, Respond', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-84', '84', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_K_002', '[ELO2 - Knowledge] Name and identify the offspring of some common animals.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-85', '85', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_K_003', '[ELO2 - Knowledge] Identify signals offspring make (crying, chirping, whining, and other vocalisations).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-86', '86', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_K_004', '[ELO2 - Knowledge] Describe how different patterns in behaviour teach survival skills.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-87', '87', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_S_001', '[ELO2 - Skills] Observe (either first-hand or through media) how parents and offspring behave to help them to survive.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-88', '88', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_S_002', '[ELO2 - Skills] Demonstrate through role play the patterns of behaviour that offspring make and the parent''s responses.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-89', '89', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_S_003', '[ELO2 - Skills] Infer from the offspring''s signal, the parent''s response (e.g. feeding, comforting and protecting the offspring).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
