  ('legacy-sco-91', '91', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_S_005', '[ELO2 - Skills] Communicate their observations of parent-offspring behaviours.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-92', '92', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_AV_001', '[ELO2 - Attitudes/Values] Appreciate that parents and offspring work together to survive.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
