  ('legacy-sco-96', '96', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_AV_005', '[ELO2 - Attitudes/Values] When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-97', '97', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_2_AV_006', '[ELO2 - Attitudes/Values] Participate actively in classroom discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-98', '98', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_3_K_001', '[ELO3 - Knowledge] Define the terms: parent, roots, Leaves, Stems, Fruits, flowers, body coverings', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-99', '99', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_3_K_002', '[ELO3 - Knowledge] Identify the properties of plants that allow you to distinguish between parents and offspring.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00'),
  ('legacy-sco-100', '100', 'science', '1', 'Structure, Function and Information Processing', 'SC_G1_ST2_3_K_003', '[ELO3 - Knowledge] Identify the properties of animals that allow you to distinguish between parents and offspring.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure, Function and Information Processing', '2026-01-01T01:25:12.564043+00:00', '2026-01-01T01:25:12.564043+00:00');
