  ('legacy-sco-128', '127', 'science', 'K', 'Interdependent Relationships in Ecosystems: Animals, Plants, and Their Environment', 'SC_GK_ST2_ELO2_K_007', '[ELO2 - Knowledge] Understand that some animals need different kinds of food to survive from other animals', NULL, NULL, NULL, NULL, NULL, NULL, 'Interdependent Relationships in Ecosystems: Animals, Plants, and Their Environment', '2026-01-01T02:00:17.75147+00:00', '2026-01-01T02:00:17.75147+00:00'),
