  ('legacy-sco-132', '131', 'science', 'K', 'Interdependent Relationships in Ecosystems: Animals, Plants, and Their Environment', 'SC_GK_ST2_ELO3_K_002', '[ELO3 - Knowledge] Create a model to show where a plant or animal lives and what they find there that helps them to survive.', NULL, NULL, NULL, NULL, NULL, NULL, 'Interdependent Relationships in Ecosystems: Animals, Plants, and Their Environment', '2026-01-01T02:00:17.75147+00:00', '2026-01-01T02:00:17.75147+00:00'),
