  ('legacy-sco-389', '2172', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_005', '[ELO1 - Attitudes/Values] Foster a habit of inquiry into the atomic composition of simple molecules and extended structures.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
