  ('legacy-sco-391', '2174', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_007', '[ELO1 - Attitudes/Values] Work collaboratively with group members and other members of the class to produce the models, make presentations, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-392', '2175', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_008', '[ELO1 - Attitudes/Values] Develop a sense of stewardship towards the environment and respect for living organisms affected by energy choices.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-393', '2176', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_009', '[ELO1 - Attitudes/Values] Participate in a class discussion of their ideas and opinions related to atomic composition.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-394', '2177', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_010', '[ELO1 - Attitudes/Values] When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-395', '2178', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_011', '[ELO1 - Attitudes/Values] Analyze structures to ensure faithfulness to the design.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-396', '2179', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_001', '[ELO2 - Knowledge] Define the terms: Natural resources, Natural products, Synthetic materials, Chemical process, Impact on society.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-397', '2180', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_002', '[ELO2 - Knowledge] Identify a production process to produce synthetics, taking place in the home or industry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-398', '2181', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_003', '[ELO2 - Knowledge] Explain how polymers are formed.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-399', '2182', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_004', '[ELO2 - Knowledge] Describe the different types of natural resources and provide examples of how each could be used in the production of synthetic materials.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-400', '2183', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_005', '[ELO2 - Knowledge] Classify synthetic materials into categories (e.g., plastics, synthetic fibres, medicines, alternative fuels) and discuss their specific applications in daily life.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-401', '2184', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_006', '[ELO2 - Knowledge] Understand that human production processes make goods and products which may impact the environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-402', '2185', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_007', '[ELO2 - Knowledge] Compare and contrast the properties of natural products and synthetic materials (e.g., durability, biodegradability, cost of production, environmental impact).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-403', '2186', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_008', '[ELO2 - Knowledge] Discuss the role of chemistry in society, specifically how advancements in chemical processes have led to the development of new materials with significant societal benefits (e.g., medical advancements, diet alternatives, food safety).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-404', '2187', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_009', '[ELO2 - Knowledge] Explore the relationship between resource scarcity and the need for synthetic alternatives (e.g., the use of synthetic rubber during wartime shortages of natural rubber).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-405', '2188', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_010', '[ELO2 - Knowledge] Understand that technological processes include manufacturing and constructing that may have an impact on their lives.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-406', '2189', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_011', '[ELO2 - Knowledge] Understand the environmental implications of both the production and disposal of synthetic materials (e.g., pollution from plastic waste, energy use in manufacturing processes).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-407', '2190', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_012', '[ELO2 - Knowledge] Identify careers related to the development and management of synthetic materials (e.g., chemical engineering, environmental science, materials science, waste management).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-408', '2191', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_013', '[ELO2 - Knowledge] Investigate future trends in synthetic material development, including sustainable alternatives (e.g., bioplastics) and their potential to reduce environmental impact.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-409', '2192', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_001', '[ELO2 - Skills] Differentiate between natural resources, natural products, and synthetic materials by analysing their origins and processes of transformation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-410', '2193', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_002', '[ELO2 - Skills] Identify examples of common synthetic materials and explain the natural resources from which they are derived.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-411', '2194', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_003', '[ELO2 - Skills] Analyse the positive and negative impacts of synthetic materials on society, including economic, environmental, and health effects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-412', '2195', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_004', '[ELO2 - Skills] Research and present findings on a synthetic material''s impact on society, showing the connection between natural resources and synthetic products.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-413', '2196', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_005', '[ELO2 - Skills] Undertake simple calculations to project impact of synthetic materials on cost of living, disposal, landfill and environment (e.g. diapers).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-414', '2197', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_006', '[ELO2 - Skills] Critically evaluate the societal implications of synthetic material production, such as plastic pollution or advancements in medicine.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-415', '2198', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_001', '[ELO2 - Attitudes/Values] Appreciate the importance of natural resources in the production of synthetic materials, recognizing the balance needed between resource use and environmental sustainability.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-416', '2199', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_002', '[ELO2 - Attitudes/Values] Appreciate that people use production processes to change materials to satisfy their needs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-417', '2200', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_003', '[ELO2 - Attitudes/Values] Develop environmental awareness by reflecting on the environmental consequences of synthetic material use and promoting practices that minimize harm.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-418', '2201', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_004', '[ELO2 - Attitudes/Values] Respect scientific innovation by understanding how synthetic materials have contributed to societal advancements, while also considering ethical implications.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-419', '2202', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_005', '[ELO2 - Attitudes/Values] Value collaboration and open-mindedness when engaging in group projects and discussions, listening to and considering diverse perspectives.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-420', '2203', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_006', '[ELO2 - Attitudes/Values] Cultivate critical thinking about the use of synthetic materials in everyday life and the potential future challenges and opportunities they present.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-421', '2204', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_001', '[ELO1 - Knowledge] Define the terms: Water vapor, Phase or state change, Physical change, Chemical change, Starting materials, Products, Reactants, Acrid smell, Closed system, Waft, Endothermic reaction, Law of Conservation of Mass, Collisions, Precipitate, Hard and soft water, Soap scum, Exothermic reaction, Combustion.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-422', '2205', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_002', '[ELO1 - Knowledge] Demonstrate they understand the difference between physical and chemical changes by giving examples of each.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-423', '2206', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_003', '[ELO1 - Knowledge] Demonstrate they understand the range of indicators of chemical change by giving examples of each.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-424', '2207', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_004', '[ELO1 - Knowledge] Explain how a burning splint can be used to assess which of the following gases are being released in a chemical reaction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-425', '2208', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_005', '[ELO1 - Knowledge] Demonstrate they understand that when a chemical reaction has occurred, new substances (products) are formed that have different properties than the original substances (reactants).', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-426', '2209', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_006', '[ELO1 - Knowledge] Demonstrate they understand that when two chemical compounds react, the atoms are rearranged to form new products.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-427', '2210', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_007', '[ELO1 - Knowledge] Differentiate between endothermic and exothermic chemical reaction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-428', '2211', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_001', '[ELO1 - Skills] Infer what will happen when certain substances react.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-429', '2212', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_002', '[ELO1 - Skills] Hypothesize the changes that would take place after reactants are mixed.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-430', '2213', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_003', '[ELO1 - Skills] Represent data collected from chemical reactions in the form of a graph or table.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
