  ('legacy-sco-432', '2215', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_005', '[ELO1 - Skills] Exercise the wafting technique.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-433', '2216', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_006', '[ELO1 - Skills] Analyze and interpret observations to make conclusions about indicators of chemical change.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
