  ('legacy-sco-435', '2218', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_008', '[ELO1 - Skills] Classify endo and exothermic processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-436', '2219', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_009', '[ELO1 - Skills] Measure temperature changes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
