INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-451', '1933', 'science', '5', 'Structure and Properties of Matter', 'SC_G5_ST1_ELO1_K_011', '[ELO1 - Knowledge] Compare different states of matter in terms of the arrangement and movement of their particles.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T03:43:33.548522+00:00', '2026-01-01T03:43:33.548522+00:00'),
