  ('legacy-sco-649', '2348', 'science', '6', 'Waves and Electromagnetic Radiation', 'SC_G6_ST4_ELO2_S_004', '[ELO2 - Skills] Analyze data from observations and experiments to draw conclusions about wave behavior.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves and Electromagnetic Radiation', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-650', '2349', 'science', '6', 'Waves and Electromagnetic Radiation', 'SC_G6_ST4_ELO2_S_005', '[ELO2 - Skills] Interpret graphs or pictures of wave interactions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves and Electromagnetic Radiation', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-651', '2350', 'science', '6', 'Waves and Electromagnetic Radiation', 'SC_G6_ST4_ELO2_AV_001', '[ELO2 - Attitudes/Values] Learners will develop interest and curiosity about wave behaviors by asking questions and doing research.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves and Electromagnetic Radiation', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-652', '2351', 'science', '6', 'Waves and Electromagnetic Radiation', 'SC_G6_ST4_ELO2_AV_002', '[ELO2 - Attitudes/Values] Learners will demonstrate respect for peers during group work activities and discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves and Electromagnetic Radiation', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-653', '2352', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_001', '[ELO1 - Knowledge] Define the terms: Force, Magnitude, Free-body diagram, Action, Reaction, Collision.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-654', '2354', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_003', '[ELO1 - Knowledge] Identify action and reaction forces in everyday life.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-655', '2355', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_004', '[ELO1 - Knowledge] Describe the effects of action and reaction forces on colliding objects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-656', '2356', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_005', '[ELO1 - Knowledge] Explain how we can apply Newton''s Third Law of Motion to car safety.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-657', '2357', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_S_001', '[ELO1 - Skills] Observe that Newton''s third law describes an equal and opposite force acting on two objects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-658', '2358', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_S_002', '[ELO1 - Skills] Create a balloon rocket model to test Newton''s third law that for every reaction there is an equal and opposite reaction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-659', '2359', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_S_003', '[ELO1 - Skills] Design and build a unique toy car to test how we can absorb an equal and opposite force acting on colliding objects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-660', '2360', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_S_004', '[ELO1 - Skills] Draw free-body diagrams to represent opposing forces.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-661', '2361', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_001', '[ELO1 - Attitudes/Values] To develop interest and curiosity in motion and the laws which govern it.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-662', '2362', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_002', '[ELO1 - Attitudes/Values] To develop an interest and curiosity in how Newton''s laws are applied to practical problems such as car safety.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-663', '2363', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_003', '[ELO1 - Attitudes/Values] To persist in problem-solving of practical experiments despite failure.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-664', '2364', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_004', '[ELO1 - Attitudes/Values] When conducting practical and group work, display sensitivity and help peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-665', '2365', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_005', '[ELO1 - Attitudes/Values] Participate actively in classroom discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-666', '2366', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_AV_006', '[ELO1 - Attitudes/Values] Consider a career in the automotive design field.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-667', '2367', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_K_001', '[ELO2 - Knowledge] Define the terms: force, balanced/unbalanced force, mass, Newton (N), pull/push, speed/velocity, inertia, motion, friction, gravity, momentum, acceleration, elastic collision, inelastic collision, direction/position, net force, Newton''s laws.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-668', '2368', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_K_002', '[ELO2 - Knowledge] Demonstrate that an object in motion stays in motion and an object at rest remains at rest with the same speed and same direction unless acted upon by a force.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-669', '2369', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_K_003', '[ELO2 - Knowledge] Compare how the mass and speed of objects upon impact will determine in what direction they will move.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-670', '2370', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_K_004', '[ELO2 - Knowledge] Explain that a bigger and heavier object has greater inertia and requires more force to move it.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-671', '2371', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_K_005', '[ELO2 - Knowledge] Distinguish elastic and inelastic collisions qualitatively (bouncy vs. sticky).', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-672', '2372', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_001', '[ELO2 - Skills] Predict the outcome of collisions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-673', '2373', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_002', '[ELO2 - Skills] Calculate net force for simple aligned or opposing forces.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-674', '2374', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_003', '[ELO2 - Skills] Observe the mass of objects, the speed at which they move and direction these objects end up after a collision.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-675', '2375', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_004', '[ELO2 - Skills] Infer what will happen if two objects of the same mass, moving at same speed in opposite directions collide.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-676', '2376', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_005', '[ELO2 - Skills] Predict the direction an object will go with different mass, velocity and moving in the opposite direction upon collision.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
  ('legacy-sco-677', '2377', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO2_S_006', '[ELO2 - Skills] Carry out experiments to develop an intuition that both the mass and the speed will impact where the joined mass will end up after they collide.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:35:59.57518+00:00', '2026-01-01T04:35:59.57518+00:00'),
