  ('legacy-sco-701', '2402', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_001', '[ELO1 - Knowledge] Define the terms: Atom, Molecule, Nucleus, Proton, Neutron, Electron, Charge, Element, Bonds, Molecular formula, Tetrahedron, Lattice structures, Diamond, Graphite, Lubricant.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
