  ('legacy-sco-703', '2404', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_003', '[ELO1 - Knowledge] Compare atomic particles in the nucleus and those that orbit the nucleus.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-704', '2405', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_004', '[ELO1 - Knowledge] Show how atoms can be combined to make molecules.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-705', '2406', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_005', '[ELO1 - Knowledge] Account for the difference that structure makes in properties of graphite and diamond.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-706', '2407', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_006', '[ELO1 - Knowledge] Explain how the number of electrons and protons in an atom contributes to its charge.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-707', '2408', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_K_007', '[ELO1 - Knowledge] Distinguish between 2D and 3D structures (water vs. methane).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-708', '2409', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_001', '[ELO1 - Skills] Calculate charge on an atom.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-709', '2410', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_002', '[ELO1 - Skills] Make models to reflect molecular formula.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-710', '2411', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_003', '[ELO1 - Skills] Classify atomic particles.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-711', '2412', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_004', '[ELO1 - Skills] Research natural product medicines originating from molecules.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-712', '2413', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_005', '[ELO1 - Skills] Communicate research findings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-713', '2414', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_S_006', '[ELO1 - Skills] Investigate structures using online simulations and viewers.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-714', '2415', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_001', '[ELO1 - Attitudes/Values] Appreciation that understanding atoms and molecules helps us plan important research and development to meet human needs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-715', '2416', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_002', '[ELO1 - Attitudes/Values] Persistence in investigating structures of molecules we can''t see.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-716', '2417', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_003', '[ELO1 - Attitudes/Values] Interest/Curiosity in how atoms are assembled to make important molecules.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-717', '2418', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_004', '[ELO1 - Attitudes/Values] Be persistent in developing models of varying complexity.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-718', '2419', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_005', '[ELO1 - Attitudes/Values] Foster a habit of inquiry into the atomic composition of simple molecules and extended structures.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-719', '2420', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_006', '[ELO1 - Attitudes/Values] Demonstrate resourcefulness as they use everyday materials to develop models.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-720', '2421', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_007', '[ELO1 - Attitudes/Values] Work collaboratively with group members and other members of the class to produce the models, make presentations, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-721', '2422', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_008', '[ELO1 - Attitudes/Values] Develop a sense of stewardship towards the environment and respect for living organisms affected by energy choices.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-722', '2423', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_009', '[ELO1 - Attitudes/Values] Participate in a class discussion of their ideas and opinions related to atomic composition.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-723', '2424', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_010', '[ELO1 - Attitudes/Values] When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-724', '2425', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO1_AV_011', '[ELO1 - Attitudes/Values] Analyze structures to ensure faithfulness to the design.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-725', '2426', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_001', '[ELO2 - Knowledge] Define the terms: Natural resources, Natural products, Synthetic materials, Chemical process, Impact on society.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-726', '2427', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_002', '[ELO2 - Knowledge] Identify a production process to produce synthetics, taking place in the home or industry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-727', '2428', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_003', '[ELO2 - Knowledge] Explain how polymers are formed.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-728', '2429', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_004', '[ELO2 - Knowledge] Describe the different types of natural resources and provide examples of how each could be used in the production of synthetic materials.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-729', '2430', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_005', '[ELO2 - Knowledge] Classify synthetic materials into categories (e.g., plastics, synthetic fibres, medicines, alternative fuels) and discuss their specific applications in daily life.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-730', '2431', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_006', '[ELO2 - Knowledge] Understand that human production processes make goods and products which may impact the environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-731', '2432', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_007', '[ELO2 - Knowledge] Compare and contrast the properties of natural products and synthetic materials (e.g., durability, biodegradability, cost of production, environmental impact).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-732', '2433', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_008', '[ELO2 - Knowledge] Discuss the role of chemistry in society, specifically how advancements in chemical processes have led to the development of new materials with significant societal benefits (e.g., medical advancements, diet alternatives, food safety).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-733', '2434', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_009', '[ELO2 - Knowledge] Explore the relationship between resource scarcity and the need for synthetic alternatives (e.g., the use of synthetic rubber during wartime shortages of natural rubber).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-734', '2435', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_010', '[ELO2 - Knowledge] Understand that technological processes include manufacturing and constructing that may have an impact on their lives.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-735', '2436', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_011', '[ELO2 - Knowledge] Understand the environmental implications of both the production and disposal of synthetic materials (e.g., pollution from plastic waste, energy use in manufacturing processes).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-736', '2437', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_012', '[ELO2 - Knowledge] Identify careers related to the development and management of synthetic materials (e.g., chemical engineering, environmental science, materials science, waste management).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-737', '2438', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_K_013', '[ELO2 - Knowledge] Investigate future trends in synthetic material development, including sustainable alternatives (e.g., bioplastics) and their potential to reduce environmental impact.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-738', '2439', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_001', '[ELO2 - Skills] Differentiate between natural resources, natural products, and synthetic materials by analysing their origins and processes of transformation.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-739', '2440', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_002', '[ELO2 - Skills] Identify examples of common synthetic materials and explain the natural resources from which they are derived.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-740', '2441', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_003', '[ELO2 - Skills] Analyse the positive and negative impacts of synthetic materials on society, including economic, environmental, and health effects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-741', '2442', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_004', '[ELO2 - Skills] Research and present findings on a synthetic material''s impact on society, showing the connection between natural resources and synthetic products.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-742', '2443', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_005', '[ELO2 - Skills] Undertake simple calculations to project impact of synthetic materials on cost of living, disposal, landfill and environment (e.g. diapers).', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-743', '2444', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_S_006', '[ELO2 - Skills] Critically evaluate the societal implications of synthetic material production, such as plastic pollution or advancements in medicine.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-744', '2445', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_001', '[ELO2 - Attitudes/Values] Appreciate the importance of natural resources in the production of synthetic materials, recognizing the balance needed between resource use and environmental sustainability.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-745', '2446', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_002', '[ELO2 - Attitudes/Values] Appreciate that people use production processes to change materials to satisfy their needs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-746', '2447', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_003', '[ELO2 - Attitudes/Values] Develop environmental awareness by reflecting on the environmental consequences of synthetic material use and promoting practices that minimize harm.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-747', '2448', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_004', '[ELO2 - Attitudes/Values] Respect scientific innovation by understanding how synthetic materials have contributed to societal advancements, while also considering ethical implications.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-748', '2449', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_005', '[ELO2 - Attitudes/Values] Value collaboration and open-mindedness when engaging in group projects and discussions, listening to and considering diverse perspectives.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-749', '2450', 'science', '6', 'Structure and Properties of Matter', 'SC_G6_ST1_ELO2_AV_006', '[ELO2 - Attitudes/Values] Cultivate critical thinking about the use of synthetic materials in everyday life and the potential future challenges and opportunities they present.', NULL, NULL, NULL, NULL, NULL, NULL, 'Structure and Properties of Matter', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-750', '2451', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_001', '[ELO1 - Knowledge] Define the terms: Water vapor, Phase or state change, Physical change, Chemical change, Starting materials, Products, Reactants, Acrid smell, Closed system, Waft, Endothermic reaction, Law of Conservation of Mass, Collisions, Precipitate, Hard and soft water, Soap scum, Exothermic reaction, Combustion.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-751', '2452', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_002', '[ELO1 - Knowledge] Demonstrate they understand the difference between physical and chemical changes by giving examples of each.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-752', '2453', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_003', '[ELO1 - Knowledge] Demonstrate they understand the range of indicators of chemical change by giving examples of each.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-753', '2454', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_004', '[ELO1 - Knowledge] Explain how a burning splint can be used to assess which of the following gases are being released in a chemical reaction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-754', '2455', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_005', '[ELO1 - Knowledge] Demonstrate they understand that when a chemical reaction has occurred, new substances (products) are formed that have different properties than the original substances (reactants).', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-755', '2456', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_006', '[ELO1 - Knowledge] Demonstrate they understand that when two chemical compounds react, the atoms are rearranged to form new products.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-756', '2457', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_K_007', '[ELO1 - Knowledge] Differentiate between endothermic and exothermic chemical reaction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-757', '2458', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_001', '[ELO1 - Skills] Infer what will happen when certain substances react.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-758', '2459', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_002', '[ELO1 - Skills] Hypothesize the changes that would take place after reactants are mixed.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-759', '2460', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_003', '[ELO1 - Skills] Represent data collected from chemical reactions in the form of a graph or table.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-760', '2461', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_004', '[ELO1 - Skills] Make careful observations of demonstrations and experiments.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-761', '2462', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_005', '[ELO1 - Skills] Exercise the wafting technique.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-762', '2463', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO1_S_006', '[ELO1 - Skills] Analyze and interpret observations to make conclusions about indicators of chemical change.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
