  ('legacy-sco-785', '2486', 'science', '6', 'Chemical Reactions', 'SC_G6_ST2_ELO2_K_001', '[ELO2 - Knowledge] Define the terms: Conservation of matter (mass), Effervescent tablets, Methane, Combustion reaction, Reactants, Products, Open system, Oxidation reaction, Atoms vs molecules, Coefficients, Subscripts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Chemical Reactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
