INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-901', '2602', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_004', '[ELO1 - Knowledge] Describe the effects of action and reaction forces on colliding objects.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
  ('legacy-sco-902', '2603', 'science', '6', 'Forces and Interactions', 'SC_G6_ST5_ELO1_K_005', '[ELO1 - Knowledge] Explain how we can apply Newton''s Third Law of Motion to car safety.', NULL, NULL, NULL, NULL, NULL, NULL, 'Forces and Interactions', '2026-01-01T04:40:40.068592+00:00', '2026-01-01T04:40:40.068592+00:00'),
