  ('legacy-sco-1137', '2837', 'science', '4', 'Energy', 'SC_G4_ST1_ELO5_AV_014', '[ELO5 - Attitudes/Values] Participate in a simulation activity and conduct research and create a project that will be used to teach others about alternative/renewable energy sources.', NULL, NULL, NULL, NULL, NULL, NULL, 'Energy', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
