  ('legacy-sco-1201', '2903', 'science', '4', 'Waves', 'SC_G4_ST2_ELO1_AV_004', '[ELO1 - Attitudes/Values] Use the inquiry approach to investigate wave characteristics and wave motion.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
