  ('legacy-sco-1204', '2906', 'science', '4', 'Waves', 'SC_G4_ST2_ELO1_AV_007', '[ELO1 - Attitudes/Values] Work collaboratively in the investigation of waves and the production of models of waves.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1205', '2907', 'science', '4', 'Waves', 'SC_G4_ST2_ELO1_AV_008', '[ELO1 - Attitudes/Values] Ensure when investigating waves in the environment e.g. throwing stones into water bodies, or making sounds, that animals are not affected.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1206', '2908', 'science', '4', 'Waves', 'SC_G4_ST2_ELO1_AV_009', '[ELO1 - Attitudes/Values] When investigating waves, ensure that safety rules are followed, especially when using items such as ropes and slinky to produce waves.', NULL, NULL, NULL, NULL, NULL, NULL, 'Waves', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
