  ('legacy-sco-1360', '3062', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_S_008', '[ELO2 - Skills] Communicate experimental results by making a model.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1361', '3063', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_AV_001', '[ELO2 - Attitudes/Values] When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1362', '3064', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_AV_002', '[ELO2 - Attitudes/Values] Express the desire to explore the factors that contribute to weathering and erosion and contribute solutions to erosion challenges in your community.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1363', '3065', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_AV_003', '[ELO2 - Attitudes/Values] Show concern and present community solutions to the problems of deforestation which leads to erosion, and eventually global warming.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1364', '3066', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_AV_004', '[ELO2 - Attitudes/Values] Consider solutions to solve the problem of flooding/run-off that washes away arable lands.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1365', '3067', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO2_AV_005', '[ELO2 - Attitudes/Values] Participate actively in classroom discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1366', '3068', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_001', '[ELO3 - Knowledge] Define the following terms: Map, Globe, Boundary, Continent, Mountain, Mountain Range, Volcano, Ocean, Ocean trenches, Crust, Ridge, Earthquake, Features, Landscape, Pangaea, Continental drift, Tectonic plates, Complementary shapes, Lithosphere, Oceanic crust, Continental Crust, Convergent Boundaries, Divergent Boundaries, Transform fault, Mountain ranges, Summit, Base, Folded Mountains, Fault Block Mountain, Dome Mountains, Continental Shelf, Oceanic Trench, Abyssal Plain, Continental Slope, Continental Rise, Elevation, Contour lines.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1367', '3069', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_002', '[ELO3 - Knowledge] Identify on a world map and diagram: mountains, continents, oceans, ocean floor structures, volcanoes and earthquakes areas.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1368', '3070', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_003', '[ELO3 - Knowledge] Identify patterns in the location of the earth''s features, e.g. locations of mountain ranges, ocean floor structures, earthquakes and volcanoes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1369', '3071', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_004', '[ELO3 - Knowledge] Explain the concept of continental drift.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1370', '3072', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_005', '[ELO3 - Knowledge] Relay the evidence and logic that continental drift of the tectonic plates is a viable theory.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1371', '3073', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_006', '[ELO3 - Knowledge] Demonstrate an understanding of the use of the terms tectonic plate continent, ocean, mountain range, volcano, earthquake, ocean trench, ocean floor, etc. by using drawings and descriptions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1372', '3074', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_007', '[ELO3 - Knowledge] Explain that mountains, volcanoes, earthquakes and ocean trenches are formed because of the movement of tectonic plates.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1373', '3075', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_008', '[ELO3 - Knowledge] Explain how the knowledge of the location of mountains, earthquakes and volcanoes affects the lives of people.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1374', '3076', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_009', '[ELO3 - Knowledge] Describe an earthquake as a natural occurrence and explain what causes it.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1375', '3077', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_010', '[ELO3 - Knowledge] Identify volcanic activity as a natural process and explain how volcanoes are formed, as well as the likely impact on the environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1376', '3078', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_011', '[ELO3 - Knowledge] Identify ways in which earthquakes impact the environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1377', '3079', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_012', '[ELO3 - Knowledge] Describe the safety measures to be put in practice during an earthquake, explaining the need for each measure.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1378', '3080', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_013', '[ELO3 - Knowledge] Explain how volcanoes are formed and discuss the impact that these eruptions cause.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1379', '3081', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_K_014', '[ELO3 - Knowledge] Outline useful and harmful effects of the presence of a volcano in their environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1380', '3082', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_001', '[ELO3 - Skills] Draw diagrams or formulate models to represent some features of the earth, e.g. an ocean floor, continents, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1381', '3083', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_002', '[ELO3 - Skills] Predict locations where earthquakes or volcanoes could take place.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1382', '3084', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_003', '[ELO3 - Skills] Use crayons/markers/seeds to locate features of the earth on a blank map, e.g. continents, mountain ranges, volcanoes, trenches, etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1383', '3085', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_004', '[ELO3 - Skills] Draw diagrams that show that you understand three ways plate boundaries can interact (divergent, convergent and transform).', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1384', '3086', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_005', '[ELO3 - Skills] Account for how plate interactions can create mountains and furthermore cause earthquakes and volcanoes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1385', '3087', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_006', '[ELO3 - Skills] Identify mountains and/or volcanoes in your country and account for why volcanic activity is prevalent in the Caribbean region.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1386', '3088', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_S_007', '[ELO3 - Skills] Effectively communicate information based on observation of patterns of the earth''s features.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1387', '3089', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_AV_001', '[ELO3 - Attitudes/Values] Actively participate in class discussions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1388', '3090', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_AV_002', '[ELO3 - Attitudes/Values] When conducting group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1389', '3091', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_AV_003', '[ELO3 - Attitudes/Values] Work respectfully with each other while analysing maps and charts and videos to describe patterns of earth''s features.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1390', '3092', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO3_AV_004', '[ELO3 - Attitudes/Values] Develop awareness that earth events and changes in earth''s feature can affect the environment and the lives and habitats of living things.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1391', '3093', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_001', '[ELO4 - Knowledge] Define the terms: Earthquake, Flood, Volcanic eruption, Tsunami, Hurricane, Mudslides, Risk assessment, Risk reduction.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1392', '3094', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_002', '[ELO4 - Knowledge] Describe causes of: Earthquakes, Hurricanes, floods, tsunamis, volcanic eruptions, mudslides.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1393', '3095', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_003', '[ELO4 - Knowledge] Describe mechanisms of: Earthquakes, Hurricanes, floods, tsunamis, volcanic eruptions, mudslides.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1394', '3096', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_004', '[ELO4 - Knowledge] Assess risks associated with natural earth processes (hurricanes, floods, tsunami and earthquakes).', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1395', '3097', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_005', '[ELO4 - Knowledge] Demonstrate an understanding of monitoring systems used for detection of different natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1396', '3098', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_006', '[ELO4 - Knowledge] Explain the significance of early warning signals in reducing the impact of natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1397', '3099', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_007', '[ELO4 - Knowledge] Demonstrate an understanding of structural factors that contribute to the stability of buildings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1398', '3100', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_008', '[ELO4 - Knowledge] Apply understanding of structural principles to ensure that buildings can withstand seismic forces.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1399', '3101', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_009', '[ELO4 - Knowledge] Describe methods of reducing flooding and the impacts of flooding.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1400', '3102', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_010', '[ELO4 - Knowledge] Apply understanding of structural principles to designing of buildings that are able to withstand the force of a tsunami.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00');
