  ('legacy-sco-1405', '3107', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_015', '[ELO4 - Knowledge] Explain how volcanoes are formed and discuss the impact that these eruptions cause.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1406', '3108', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_K_016', '[ELO4 - Knowledge] Outline useful and harmful effects of the presence of a volcano in their environment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1407', '3109', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_001', '[ELO4 - Skills] Brainstorm with peers the ways to reduce the impact or prepare for forces of nature such as hurricanes, volcanoes, mudslides etc.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1408', '3110', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_002', '[ELO4 - Skills] Identify the problems in their community with respect to the natural forces.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1409', '3111', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_003', '[ELO4 - Skills] Problem solve solutions to the challenges that arise form natural forces.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1410', '3112', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_004', '[ELO4 - Skills] Secure feedback from leaders of the community on how to prepare for and mitigate problems.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1411', '3113', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_005', '[ELO4 - Skills] Predict how a building''s design would affect its ability to withstand the effect of natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1412', '3114', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_006', '[ELO4 - Skills] Observe and identify features of buildings that make them resilient to natural earth process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1413', '3115', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_007', '[ELO4 - Skills] Design a simple earth-resistant structure using everyday material.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1414', '3116', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_S_008', '[ELO4 - Skills] Design a simple structure that would be appropriate for a tsunami prone area.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1415', '3117', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_AV_001', '[ELO4 - Attitudes/Values] Develop a sense of concern for persons affected by natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1416', '3118', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_AV_002', '[ELO4 - Attitudes/Values] Appreciate the importance of developing resilient structures that can withstand the effects of natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1417', '3119', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_AV_003', '[ELO4 - Attitudes/Values] Appreciate the importance of paying attention to early warning signals so as to reduce the impact of natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1418', '3120', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_AV_004', '[ELO4 - Attitudes/Values] Value practices that lead to flood prevention.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1419', '3121', 'science', '4', 'Earth Systems: Processes that Shape the Earth', 'SC_G4_ST4_ELO4_AV_005', '[ELO4 - Attitudes/Values] Recognize the importance of teamwork and collaboration in mitigating against the effects of natural earth processes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Earth Systems: Processes that Shape the Earth', '2026-01-01T04:59:36.181636+00:00', '2026-01-01T04:59:36.181636+00:00'),
  ('legacy-sco-1420', '1', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.1', '[ELO1] Listen to music, conversation, and environmental sounds for personal enjoyment.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1421', '2', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.2', '[ELO1] Demonstrate interest, curiosity, engagement in sharing the experiences of others and with oral stories and information sharing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1422', '3', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.3', '[ELO1] Use social listening and speaking skills to interact with a variety of audiences with sensitivity and respect.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1423', '4', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.4', '[ELO1] Interact and collaborate with the teacher and children who have diverse interests, backgrounds, and languages.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1424', '5', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.5', '[ELO1] Become aware of how effective listening enhances understanding.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1425', '6', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.6', '[ELO1] Observe how tone, fluency and intonation impact meaning and mood.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1426', '7', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.7', '[ELO1] Use Home Language(s) and, as Standard English develops, share their thoughts, feelings, and questions about engaging events, stories, and conversations with increasing confidence.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1427', '8', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.8', '[ELO1] Develop increasing clarity and focus when sharing stories or experiences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1428', '9', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.9', '[ELO1] Engage in active phonological awareness activities and word play to discriminate between various sounds in their environment, letters of the alphabet, rhyme, and meaningful sound patterns.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1429', '10', 'language-arts', 'K', 'Listening and Speaking', 'LA_GRK_ST1_ELO1_1.10', '[ELO1] Develop and apply vocabulary and language structures to enhance their understanding of how to communicate ideas with purpose and focus.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1430', '11', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.1', '[ELO1] Interact meaningfully with a wide range of genres and text forms.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1431', '12', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.2', '[ELO1] Develop questions when browsing through passages of interest.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1432', '13', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.3', '[ELO1] Connect background knowledge to the titles and pictures of fiction and nonfiction passages to build a foundation of understanding.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1433', '14', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.4', '[ELO1] Develop understanding and application of the Concepts of Print.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1434', '15', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.5', '[ELO1] Develop knowledge about the purpose and variety of texts that are read or read to them.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1435', '16', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.6', '[ELO1] Browse through a variety of images, and nonfiction material in pre-emergent and emergent level passages, or passages of interest, to discover information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1436', '17', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO1_2.7', '[ELO1] Demonstrate understanding of some environmental print and pictorial information.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1437', '18', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.8', '[ELO2] Begin to apply comprehension strategies to visualize, predict and connect.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1438', '19', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.9', '[ELO2] Demonstrate understanding by responding to read-alouds with images, model making, discussions, or temporary writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1439', '20', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.10', '[ELO2] Connect words and images in pre-emergent and emergent level texts to background knowledge.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1440', '21', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.11', '[ELO2] Recognise and use a variety of high frequency words of personal importance, such as names and pre-emergent level high-frequency words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1441', '22', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.12', '[ELO2] Participate in shared reading and use the meaning and flow of the language to anticipate upcoming words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1442', '23', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.13', '[ELO2] Begin to demonstrate fluency and phrasing during shared reading, independent and guided reading of emergent level passages.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1443', '24', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.14', '[ELO2] Identify an increasing number of letter names and letter sounds, beginning with those of personal importance.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1444', '25', 'language-arts', 'K', 'Reading and Viewing', 'LA_GRK_ST2_ELO2_2.15', '[ELO2] Use known letter sounds to decode upcoming words in emergent level passages.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1445', '26', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.1', '[ELO1] Use shared ideas to co-construct stories.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1446', '27', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.2', '[ELO1] Assign meaning to experimental drawing and writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1447', '28', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.3', '[ELO1] Begin expressive writing to share ideas and real and imagined topics.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1448', '29', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.4', '[ELO1] Use peer collaboration and classroom tools to assist in writing process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1449', '30', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.5', '[ELO1] Learn to print the upper and lower case letters of the alphabet.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1450', '31', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.6', '[ELO1] Connect spoken language(s) to written language and other representations (e.g., drawings).', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1451', '32', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.7', '[ELO1] Connect phonological awareness to letter shapes.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1452', '33', 'language-arts', 'K', 'Writing and Representing', 'LA_GRK_ST3_ELO1_3.8', '[ELO1] Spell name and some words of personal importance correctly.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1453', '34', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.1', '[ELO1] Choose to listen to music, poetry and stories for pleasure.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1454', '35', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.2', '[ELO1] Connect environmental sounds to meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1455', '36', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.3', '[ELO1] Use different voices in role playing to indicate tone and mood.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1456', '37', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.4', '[ELO1] Describe how musical and environmental sounds affect mood.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1457', '38', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.5', '[ELO1] Use Listening Comprehension Strategies to make and simplify meaning: ask questions, recall ideas, predict, visualise, and make connections.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1458', '39', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.6', '[ELO1] Listen to, retell, and express an opinion about the story.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1459', '40', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.7', '[ELO1] Listen to differentiate between make-believe and truth.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1460', '41', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.8', '[ELO1] Listen to follow and give direction e.g. 2-3 steps.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1461', '42', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.9', '[ELO1] Use Home Language and Standard English during speaking activities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1462', '43', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.10', '[ELO1] Use vocabulary appropriate to topic and audience.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1463', '44', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.11', '[ELO1] Use social listening and speaking skills to interact sensitively with those in class, school, and community.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1464', '45', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.12', '[ELO1] Express needs, wants, and feelings to a variety of audiences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1465', '46', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.13', '[ELO1] Show respect for different ideas and opinions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1466', '47', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.14', '[ELO1] Participate in conversations related to play and daily routines.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1467', '48', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.15', '[ELO1] Develop awareness of language diversity and the purpose of using Home Language and Standard English.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1468', '49', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.16', '[ELO1] Listen to, engage with, and discuss stories, songs, and other cultural traditions from their own and other communities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1469', '50', 'language-arts', '1', 'Listening and Speaking', 'LA_GR1_ST1_ELO1_1.17', '[ELO1] Begin to transfer meaning from oral to written language (segmentation, blending, rhyming, onset and rime, beats in a word/syllables).', NULL, NULL, NULL, NULL, NULL, NULL, 'Listening and Speaking', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1470', '51', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.1', '[ELO1] Select engaging and just right book choices for Independent Reading based on interests, difficulty level, and genre.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1471', '52', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.2', '[ELO1] Connect background knowledge to the topic, pictures, and title of fiction and nonfiction texts.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1472', '53', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.3', '[ELO1] Increase time (build stamina) while engaged in Independent Reading.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1473', '54', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.4', '[ELO1] Share books with peers that they enjoyed reading or having read to them.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1474', '55', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.5', '[ELO1] Demonstrate understanding by responding to text through artistic representations, discussions, and written responses.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1475', '56', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.6', '[ELO1] Recognize different points of view in the text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1476', '57', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO1_2.7', '[ELO1] Continue to develop an understanding and respect for diversity in text and illustrations.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1477', '58', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.1', '[ELO2] Recognize the purpose and basic similarities and differences in paper based and digital genres of fiction, nonfiction, and poetry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1478', '59', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.2', '[ELO2] Apply a variety of comprehension strategies to create meaning (activating background knowledge, determining importance, visualisation, prediction, inferring, synthesising, analysing, questions, make connections).', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1479', '60', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.3', '[ELO2] Demonstrate understanding using various responses to text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1480', '61', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.4', '[ELO2] Expand vocabulary through reading and discussing a range of topics, authors, and genres.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1481', '62', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.5', '[ELO2] Begin to connect background knowledge to support comprehension of culturally relevant text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1482', '63', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.6', '[ELO2] Develop vocabulary to express their understandings and opinions on topics, texts, and ideas.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1483', '64', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.7', '[ELO2] Decode high frequency words of increasing difficulty.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1484', '65', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.8', '[ELO2] Understand how high frequency words impact fluency.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1485', '66', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.9', '[ELO2] Continue to recognize and meaningfully apply knowledge of letter patterns to decode unfamiliar words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1486', '67', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.10', '[ELO2] Apply knowledge of word order, illustrations, text content and letter sounds to identify unknown words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1487', '68', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO2_3.11', '[ELO2] Begin to monitor for errors by cross checking phonics, meaning, and structure clues.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1488', '69', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.1', '[ELO3] Begin to become familiar with the style of local and favourite international authors.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1489', '70', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.2', '[ELO3] Engage with and participate in Shared Reading and Readers Theatre in fiction, nonfiction, and poetry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1490', '71', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.3', '[ELO3] Develop an understanding of text features such as bold print and font size adds to an author''s style.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1491', '72', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.4', '[ELO3] Ask questions of author''s purpose for writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1492', '73', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.5', '[ELO3] Continue to develop understanding and purpose of fiction, nonfiction, and poetry genres.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1493', '74', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.6', '[ELO3] Apply some text features to locate and predict information in text.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1494', '75', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.7', '[ELO3] Read and follow simple written and/or illustrated instructions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1495', '76', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.8', '[ELO3] Use text features to support individual and/or small group research on topic of interest.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1496', '77', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.9', '[ELO3] Search for answers to questions on digital sites.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1497', '78', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.10', '[ELO3] Discuss author''s use of interesting words that evoke emotions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1498', '79', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.11', '[ELO3] Create a personal word bank.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1499', '80', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.12', '[ELO3] Develop an understanding that words may have similar meanings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1500', '81', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.13', '[ELO3] Continue to develop an understanding of how written word order impacts meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
INSERT INTO curriculum_legacy_scos (id, elo_id, subject, grade_level, strand, code, description, sub_strand, sub_strand_number, elo_title, elo_number, outcome_type, section, theme, created_at, updated_at) VALUES
  ('legacy-sco-1501', '82', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.14', '[ELO3] Compare texts by same illustrator for similarities in mood.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1502', '83', 'language-arts', '1', 'Reading and Viewing', 'LA_GR1_ST2_ELO3_4.15', '[ELO3] Explore how emoticons, symbols, and shapes are used to convey or enhance meaning.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1503', '84', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.1', '[ELO1] Begin to develop strategies for the prewriting stage of the writing process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1504', '85', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.2', '[ELO1] Talk about the ideas they plan to write about.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1505', '132', 'language-arts', '2', 'Reading and Viewing', 'LA_GR2_ST2_ELO1_2.8', '[ELO1] Ask critical questions of fiction, nonfiction, and poetry.', NULL, NULL, NULL, NULL, NULL, NULL, 'Reading and Viewing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1506', '86', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.3', '[ELO1] Draft some illustrations to accompany ideas and write thoughts that match the ideas in their drawings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1507', '87', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.4', '[ELO1] Use role play to assist with brainstorming ideas.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1508', '88', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.5', '[ELO1] Begin to use simple graphic organizers to brainstorm and plan.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1509', '89', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.6', '[ELO1] Begin to become familiar with the purpose of various genres and how different genres look and sound.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1510', '90', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.7', '[ELO1] Begin to develop strategies for connecting prewriting to the drafting stages of the writing process.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1511', '91', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.8', '[ELO1] Write to match text to their brainstorm, planning and drawings.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1512', '92', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.9', '[ELO1] Begin to identify the topic, purpose, audience and form for writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1513', '93', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.10', '[ELO1] Begin to experiment with creating a draft in different forms.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1514', '94', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.11', '[ELO1] Begin to experiment with writing in simple sentences that may include descriptive words or simple transition words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1515', '95', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO1_5.12', '[ELO1] Begin to organise sentences into short paragraphs.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1516', '96', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.1', '[ELO2] Begin to develop self assessment revision strategies by rereading and discussing draft writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1517', '97', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.2', '[ELO2] Participate in peer revision opportunities.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1518', '98', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.3', '[ELO2] Begin to demonstrate an understanding of the role of Home Language and Standard English in writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1519', '99', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.4', '[ELO2] Begin to monitor for and develop self-correction strategies.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1520', '100', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.5', '[ELO2] Explore ways to add descriptive vocabulary.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1521', '101', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.6', '[ELO2] Explore sentence types to create meaningful sentences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1522', '102', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO2_6.7', '[ELO2] Review draft for standard use of simple verb tenses and simple sentences.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1523', '103', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.1', '[ELO3] Develop strategies to check and/or confirm commonly used words.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1524', '104', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.2', '[ELO3] Generate spelling of unfamiliar words based on sounds and patterns.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1525', '105', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.3', '[ELO3] Continue to develop the use of grade-level punctuation conventions.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1526', '106', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.4', '[ELO3] Begin to experiment with presenting published pieces of writing.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00'),
  ('legacy-sco-1527', '107', 'language-arts', '1', 'Writing and Representing', 'LA_GR1_ST3_ELO3_7.5', '[ELO3] Continue to refine letter formation to increase readability.', NULL, NULL, NULL, NULL, NULL, NULL, 'Writing and Representing', '2026-01-04T00:03:21.92801+00:00', '2026-01-04T00:03:21.92801+00:00');
